import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { motion, useAnimation } from "framer-motion";
import "../App.css";

const Home = () => {
  const navigate = useNavigate();
  const controls = useAnimation();

  useEffect(() => {
    const animateLight = async () => {
      await controls.start({ fill: "#ffe966", transition: { duration: 1 } });
      await controls.start({ fill: "#e7e5d5", transition: { duration: 1 } });
    };

    const interval = setInterval(animateLight, 2000);
    return () => clearInterval(interval); // ล้าง interval เมื่อ component ถูก unmount
  }, [controls]);

  return (
    <div className="background-gradient h-screen flex flex-col justify-center items-center text-center relative">
      <svg
        className="photoautomat-svg"
        width="300"
        height="400"
        viewBox="0 0 300 400"
        xmlns="http://www.w3.org/2000/svg"
      >
        <image href="/photoautomat.svg" width="300" height="400" />
        {/* ✅ ทำให้ light กระพริบ */}
        <motion.circle
          id="light"
          cx="250"
          cy="250"
          r="20"
          animate={controls}
          initial={{ fill: "#e7e5d5" }}
        />
      </svg>

      <button onClick={() => navigate("/welcome")} className="start-button">
        START
      </button>
    </div>
  );
};

export default Home;
